function showFullHistory() {
  const all = [...transactions].sort((a, b) =>
    (b.date || "").localeCompare(a.date || ""),
  );
  if (!all.length) {
    showToast(t("noOperations").split("\n")[0]);
    return;
  }
  let html = '<div class="history-list">';
  all.forEach((op) => {
    const ri = transactions.indexOf(op),
      sign = op.type === "income" ? "+" : "−";
    const palette = getCategoryUiPalette(op.category, op.type);
    const style = palette.style;
    const displaySubcategory = getDisplaySubcategoryLabel(
      op.subcategory,
      op.type,
    );
    const cardStyle = palette.hasCustomColor
      ? `border-left:4px solid ${palette.accentColor};background:linear-gradient(135deg, ${hexToRgba(
          palette.accentColor,
          document.body.classList.contains("dark") ? 0.15 : 0.1,
        )} 0%, var(--card-bg) 68%);`
      : `border-left:4px solid var(--cream-border);`;
    html += `<div class="history-item" style="${cardStyle}"><div class="history-item-info"><div class="history-item-cat"><span style="color:${palette.titleColor};font-weight:800;">${style.icon} ${esc(op.category)}</span>${displaySubcategory ? ` <span style="font-weight:700;color:${palette.subColor};">(${esc(displaySubcategory)})</span>` : ""}</div><div class="history-item-meta">${fmtDate(op.date)}${op.note ? " 📝 " + esc(op.note.substring(0, 30)) : ""}</div></div><div class="history-item-amt ${op.type}">${sign}${fmt(op.amountRub)}</div><div class="history-item-btns"><button class="icon-btn edit" data-idx="${ri}">✏️</button><button class="icon-btn delete" data-idx="${ri}">🗑</button></div></div>`;
  });
  html += `</div><div style="margin-top:16px;"><button class="btn-danger" id="clearAllHistoryBtn" style="width:100%">🗑 ${t("clearAllOps")}</button></div>`;
  const modal = createModal("fullHistoryModal", t("allHistory"), html);
  document.body.appendChild(modal);
  openModal("fullHistoryModal");
  modal.querySelectorAll(".icon-btn.edit").forEach((b) =>
    b.addEventListener("click", () => {
      closeModal("fullHistoryModal");
      setTimeout(() => openEditModal(parseInt(b.dataset.idx)), 200);
    }),
  );
  modal.querySelectorAll(".icon-btn.delete").forEach((b) =>
    b.addEventListener("click", () => {
      askConfirm(
        t("confirmDelete"),
        () => {
          const _di3 = parseInt(b.dataset.idx);
          const _dt3 = transactions[_di3];
          transactions.splice(_di3, 1);
          if (_dt3 && _dt3._initial) {
            logStartBalanceWrite("deleteOp:history", startBalanceRub, 0);
            startBalanceRub = 0;
            localStorage.removeItem("startBalanceRub");
          }
          saveAll();
          updateTopBlocks();
          renderBalanceSummary();
          renderOpsList();
          closeModal("fullHistoryModal");
          setTimeout(showFullHistory, 200);
          showToast(t("deleted"));
        },
        { icon: "🗑️" },
      );
    }),
  );
  document
    .getElementById("clearAllHistoryBtn")
    ?.addEventListener("click", () => {
      askConfirm(
        t("confirmDeleteAll"),
        () => {
          transactions = [];
          saveAll();
          updateTopBlocks();
          renderBalanceSummary();
          renderOpsList();
          closeModal("fullHistoryModal");
          showToast(t("deleted"));
        },
        {
          icon: "⚠️",
          title: t("confirmDeleteAll"),
          yesText: t("yesDeleteAll"),
        },
      );
    });
}

// ============================================================
// DATEPICKER
// ============================================================
function openDatePicker(initialDate, onSelect, options = {}) {
  const multiple = !!options.multiple;
  const parentModalId =
    typeof options.parentModalId === "string" ? options.parentModalId : "";
  const parentModal = parentModalId
    ? document.getElementById(parentModalId)
    : null;
  const parentSheet = parentModal?.querySelector(".add-modal-sheet, .modal");
  const embedInsideParent = !!parentSheet;
  const now = new Date();
  const fallbackDate = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, "0")}-${String(now.getDate()).padStart(2, "0")}`;
  let selectedDates = multiple
    ? Array.isArray(initialDate)
      ? [...new Set(initialDate.filter(Boolean))]
      : typeof initialDate === "string" && initialDate
        ? [
            ...new Set(
              initialDate
                .split(",")
                .map((d) => d.trim())
                .filter(Boolean),
            ),
          ]
        : []
    : [];
  // Если дата не передана, всегда берём СЕГОДНЯШНЮЮ локальную дату
  if (
    !initialDate ||
    (multiple && Array.isArray(initialDate) && initialDate.length === 0)
  ) {
    initialDate = fallbackDate;
  }
  const anchorDate = multiple
    ? selectedDates[0] || fallbackDate
    : initialDate || fallbackDate;
  const date = new Date(anchorDate + "T12:00:00");
  let vY = date.getFullYear(),
    vM = date.getMonth();
  const months = t("months"),
    weekdays = t("weekdaysShort");
  function rc() {
    const fd = new Date(vY, vM, 1);
    let sd = fd.getDay();
    sd = sd === 0 ? 6 : sd - 1;
    const dim = new Date(vY, vM + 1, 0).getDate();
    let dh = "";
    for (let i = 0; i < sd; i++)
      dh += `<div class="datepicker-day empty"></div>`;
    for (let d = 1; d <= dim; d++) {
      const ds = `${vY}-${String(vM + 1).padStart(2, "0")}-${String(d).padStart(2, "0")}`;
      const selected = multiple
        ? selectedDates.includes(ds)
        : initialDate === ds;
      dh += `<div class="datepicker-day${selected ? " selected" : ""}" data-date="${ds}">${d}</div>`;
    }
    const selectedSummary = multiple
      ? `<div style="margin-top:10px;font-size:12px;color:var(--text-muted);font-weight:700;">${
          {
            ru: `Выбрано дат: ${selectedDates.length}`,
            en: `Selected dates: ${selectedDates.length}`,
            ka: `არჩეული თარიღები: ${selectedDates.length}`,
          }[currentLang]
        }</div>`
      : "";
    const applyBtn = multiple
      ? `<div class="datepicker-top-actions"><button class="btn-primary" id="dpApply">${
          {
            ru: "Применить выбранные даты",
            en: "Apply selected dates",
            ka: "არჩეული თარიღების დადასტურება",
          }[currentLang]
        }</button></div>`
      : "";
    return `<div class="datepicker-header"><button class="datepicker-nav" id="dpPrev">←</button><span class="datepicker-month">${months[vM]} ${vY}</span><button class="datepicker-nav" id="dpNext">→</button></div>${applyBtn}<div class="datepicker-weekdays">${weekdays.map((w) => `<div class="datepicker-weekday">${w}</div>`).join("")}</div><div class="datepicker-days">${dh}</div>${selectedSummary}`;
  }
  const modal = createModal(
    "datepickerModal",
    t("pickDate"),
    `<style>
      #datepickerModal .datepicker-content{
        width:100%;
        min-width:0;
      }
      #datepickerModal .datepicker-top-actions{
        display:grid;
        grid-template-columns:minmax(0,1fr);
        gap:8px;
        width:100%;
        margin:10px 0 8px;
      }
      #datepickerModal .datepicker-top-actions .btn-primary{
        width:100%;
        min-width:0;
        max-width:100%;
        padding:12px 14px;
        white-space:normal;
        overflow-wrap:anywhere;
        word-break:break-word;
        text-align:center;
        line-height:1.25;
      }
      #datepickerModal .datepicker-actions{
        display:grid;
        grid-template-columns:minmax(0,1fr);
        gap:8px;
        width:100%;
        margin-top:12px;
      }
      #datepickerModal .datepicker-actions.multiple{
        grid-template-columns:repeat(2,minmax(0,1fr));
      }
      #datepickerModal .datepicker-actions .btn-primary,
      #datepickerModal .datepicker-actions .btn-secondary{
        width:100%;
        min-width:0;
        max-width:100%;
        padding:12px 14px;
        white-space:normal;
        overflow-wrap:anywhere;
        word-break:break-word;
        text-align:center;
        line-height:1.25;
      }
    </style><div class="datepicker-content"><div id="dpCal">${rc()}</div><div class="datepicker-actions${multiple ? " multiple" : ""}"><button class="btn-secondary" id="dpCancel">${t("cancel")}</button>${
      multiple
        ? `<button class="btn-secondary" id="dpClear">${
            {
              ru: "Снять все даты",
              en: "Clear all dates",
              ka: "ყველა თარიღის მოხსნა",
            }[currentLang]
          }</button>`
        : ""
    }</div></div>`,
  );
  if (embedInsideParent && parentSheet) {
    parentSheet.style.position = parentSheet.style.position || "relative";
    modal.classList.add("embedded-datepicker-modal");
    modal.style.position = "absolute";
    modal.style.inset = "0";
    modal.style.zIndex = "60";
    modal.style.padding = "12px";
    modal.style.background = "rgba(15,23,42,0.16)";
    modal.style.backdropFilter = "blur(2px)";
    modal.style.alignItems = "center";
    modal.style.justifyContent = "center";
    const modalCard = modal.querySelector(".modal");
    if (modalCard) {
      modalCard.style.width = "min(100%, 420px)";
      modalCard.style.maxWidth = "100%";
      modalCard.style.maxHeight = "calc(100% - 24px)";
      modalCard.style.margin = "0 auto";
    }
    parentSheet.appendChild(modal);
  } else {
    document.body.appendChild(modal);
  }
  openModal("datepickerModal");
  function upd() {
    document.getElementById("dpCal").innerHTML = rc();
    att();
    document.getElementById("dpApply")?.addEventListener("click", () => {
      closeModal("datepickerModal");
      onSelect(selectedDates);
    });
    document.getElementById("dpPrev").addEventListener("click", () => {
      vM--;
      if (vM < 0) {
        vM = 11;
        vY--;
      }
      upd();
    });
    document.getElementById("dpNext").addEventListener("click", () => {
      vM++;
      if (vM > 11) {
        vM = 0;
        vY++;
      }
      upd();
    });
  }
  function att() {
    document
      .querySelectorAll("#dpCal .datepicker-day[data-date]")
      .forEach((d) =>
        d.addEventListener("click", () => {
          if (multiple) {
            const picked = d.dataset.date;
            selectedDates = selectedDates.includes(picked)
              ? selectedDates.filter((x) => x !== picked)
              : [...selectedDates, picked].sort();
            upd();
            return;
          }
          closeModal("datepickerModal");
          onSelect(d.dataset.date);
        }),
      );
  }
  upd();
  document.getElementById("dpClear")?.addEventListener("click", () => {
    selectedDates = [];
    upd();
  });
  document
    .getElementById("dpCancel")
    .addEventListener("click", () => closeModal("datepickerModal"));
}

function bindTapSafeAction(el, handler, options = {}) {
  if (!el || typeof handler !== "function") return;
  const threshold = Number(options.threshold || 10);
  const state = {
    tracking: false,
    pointerId: null,
    startX: 0,
    startY: 0,
    suppressUntil: 0,
  };

  const begin = (x, y, pointerId = null) => {
    state.tracking = true;
    state.pointerId = pointerId;
    state.startX = x;
    state.startY = y;
  };

  const maybeSuppress = (x, y) => {
    if (!state.tracking) return;
    if (
      Math.abs(x - state.startX) > threshold ||
      Math.abs(y - state.startY) > threshold
    ) {
      state.suppressUntil = Date.now() + 450;
      state.tracking = false;
      state.pointerId = null;
    }
  };

  const end = (x, y, pointerId = null) => {
    if (
      state.pointerId !== null &&
      pointerId !== null &&
      state.pointerId !== pointerId
    ) {
      return;
    }
    maybeSuppress(x, y);
    state.tracking = false;
    state.pointerId = null;
  };

  el.addEventListener("pointerdown", (e) => {
    if (e.button !== undefined && e.button !== 0) return;
    begin(e.clientX, e.clientY, e.pointerId ?? null);
  });
  el.addEventListener("pointermove", (e) => {
    if (
      state.pointerId !== null &&
      e.pointerId !== undefined &&
      state.pointerId !== e.pointerId
    ) {
      return;
    }
    maybeSuppress(e.clientX, e.clientY);
  });
  el.addEventListener("pointerup", (e) => {
    end(e.clientX, e.clientY, e.pointerId ?? null);
  });
  el.addEventListener("pointercancel", () => {
    state.suppressUntil = Date.now() + 450;
    state.tracking = false;
    state.pointerId = null;
  });
  el.addEventListener(
    "touchstart",
    (e) => {
      const touch = e.touches?.[0];
      if (!touch) return;
      begin(touch.clientX, touch.clientY, null);
    },
    { passive: true },
  );
  el.addEventListener(
    "touchmove",
    (e) => {
      const touch = e.touches?.[0];
      if (!touch) return;
      maybeSuppress(touch.clientX, touch.clientY);
    },
    { passive: true },
  );
  el.addEventListener(
    "touchend",
    (e) => {
      const touch = e.changedTouches?.[0];
      if (!touch) return;
      end(touch.clientX, touch.clientY, null);
    },
    { passive: true },
  );
  el.addEventListener(
    "touchcancel",
    () => {
      state.suppressUntil = Date.now() + 450;
      state.tracking = false;
      state.pointerId = null;
    },
    { passive: true },
  );
  el.addEventListener("click", (e) => {
    if (Date.now() < state.suppressUntil) {
      e.preventDefault();
      e.stopPropagation();
      return;
    }
    handler(e);
  });
}

function openTimePickerCompact(initialTime, onSelect) {
  let hours = 9,
    minutes = 0;
  if (initialTime) {
    const parts = initialTime.split(":");
    hours = parseInt(parts[0]) || 9;
    minutes = parseInt(parts[1]) || 0;
  }

  const html = `
    <div style="display:flex;flex-direction:column;align-items:center;gap:12px;">
      <div style="display:flex;gap:8px;align-items:center;justify-content:center;">
        <div class="field-group" style="margin-bottom:0;flex:0 0 auto;width:80px;">
          <label class="field-label" style="text-align:center;">${t("hours")}</label>
          <input type="number" id="tpHours" class="modal-input" min="0" max="23" value="${hours}" 
            style="font-size:20px;font-weight:700;text-align:center;padding:8px;width:100%;">
        </div>
        <div style="font-size:24px;font-weight:900;color:var(--text-muted);margin-top:18px;">:</div>
        <div class="field-group" style="margin-bottom:0;flex:0 0 auto;width:80px;">
          <label class="field-label" style="text-align:center;">${t("minutes")}</label>
          <input type="number" id="tpMinutes" class="modal-input" min="0" max="59" value="${minutes}"
            style="font-size:20px;font-weight:700;text-align:center;padding:8px;width:100%;">
        </div>
      </div>
      <div class="modal-actions" style="width:100%;margin-top:8px;">
        <button class="btn-secondary" id="tpCancel" style="flex:1;">${t("cancel")}</button>
        <button class="btn-primary" id="tpSave" style="flex:1;">${t("save")}</button>
      </div>
    </div>
  `;

  updateHeroChipLabels(mc);
  forceHeroChipLayout(mc);

  const modal = createModal("timePickerModal", t("chooseTime"), html);
  document.body.appendChild(modal);
  openModal("timePickerModal");

  document.getElementById("tpCancel").onclick = () =>
    closeModal("timePickerModal");
  document.getElementById("tpSave").onclick = () => {
    const h = document
      .getElementById("tpHours")
      .value.toString()
      .padStart(2, "0");
    const m = document
      .getElementById("tpMinutes")
      .value.toString()
      .padStart(2, "0");
    closeModal("timePickerModal");
    onSelect(`${h}:${m}`);
  };
}

