// КАТЕГОРИИ
// ============================================================
function openAddCategoryModal(defType = "expense") {
  let sel = defType;
  let iconTouched = false;
  const initialIcon = detectEmojiByText(
    "",
    defType,
    getBaseCategoryStyle("", defType).icon,
  );
  const html = `<div class="field-group"><label class="field-label">${t("catTypeLabel")}</label><div class="cat-type-toggle"><button class="cat-type-btn expense ${defType === "expense" ? "active" : ""}" data-type="expense"><div class="cat-type-icon">💸</div><div class="cat-type-title">${t("catTypeExpenseTitle")}</div></button><button class="cat-type-btn income ${defType === "income" ? "active" : ""}" data-type="income"><div class="cat-type-icon">💰</div><div class="cat-type-title">${t("catTypeIncomeTitle")}</div></button></div></div><div class="field-group"><label class="field-label">${t("catNameLabel")}</label><input type="text" id="newCatName" class="modal-input" placeholder="${t("catNamePlaceholder")}" autofocus></div><div class="field-group"><label class="field-label">${t("iconLabel")}</label><input type="hidden" id="newCatIcon" value="${esc(
    initialIcon,
  )}"><button type="button" class="theme-swatch-btn" id="newCatIconBtn" style="width:100%;padding:14px 16px;display:flex;align-items:center;justify-content:space-between;gap:12px;"></button></div><div class="modal-actions"><button class="btn-secondary" id="addCatCancel">${t("cancel")}</button><button class="btn-primary" id="addCatSave">✚ ${t("save")}</button></div>`;
  const modal = createModal("addCatModal", t("addCatModalTitle"), html);
  document.body.appendChild(modal);
  openModal("addCatModal");
  const newCatIconSelect = document.getElementById("newCatIcon");
  const newCatIconBtn = document.getElementById("newCatIconBtn");
  const newCatNameInput = document.getElementById("newCatName");
  const syncNewCatIcon = () =>
    renderEmojiFieldButton(newCatIconBtn, newCatIconSelect?.value || "", sel);
  // Устанавливаем active класс для дефолтного типа при открытии
  modal.querySelectorAll(".cat-type-btn.active").forEach((b) => {
    b.classList.add("active-" + b.dataset.type);
  });
  syncNewCatIcon();
  newCatIconBtn?.addEventListener("click", () => {
    openEmojiPickerModal({
      selectedEmoji: newCatIconSelect?.value || "",
      allowEmpty: false,
      suggestedText: newCatNameInput?.value || "",
      type: sel,
      onPick: (emoji) => {
        iconTouched = true;
        if (newCatIconSelect) newCatIconSelect.value = emoji;
        syncNewCatIcon();
      },
    });
  });
  newCatNameInput?.addEventListener("input", () => {
    if (!iconTouched && newCatIconSelect) {
      newCatIconSelect.value = detectEmojiByText(
        newCatNameInput.value,
        sel,
        getBaseCategoryStyle("", sel).icon,
      );
      syncNewCatIcon();
    }
  });
  modal.querySelectorAll(".cat-type-btn").forEach((btn) =>
    btn.addEventListener("click", () => {
      sel = btn.dataset.type;
      modal.querySelectorAll(".cat-type-btn").forEach((b) => {
        b.classList.remove("active", "active-expense", "active-income");
      });
      btn.classList.add("active", "active-" + btn.dataset.type);
      if (!iconTouched && newCatIconSelect) {
        newCatIconSelect.value = detectEmojiByText(
          newCatNameInput?.value || "",
          sel,
          getBaseCategoryStyle("", sel).icon,
        );
      }
      syncNewCatIcon();
      haptic && haptic("light");
    }),
  );
  document
    .getElementById("addCatCancel")
    .addEventListener("click", () => closeModal("addCatModal"));
  document.getElementById("addCatSave").addEventListener("click", () => {
    const name = document.getElementById("newCatName").value.trim();
    if (!name) {
      showToast(t("enterCategoryName"), "error");
      return;
    }
    if (sel === "expense") {
      if (categories[name]) {
        showToast("⚠️ " + name, "error");
        return;
      }
      categories[name] = { subcats: [] };
    } else {
      if (incomeCategories[name]) {
        showToast("⚠️ " + name, "error");
        return;
      }
      incomeCategories[name] = { subcats: [] };
    }
    const baseStyle = getBaseCategoryStyle(name, sel);
    const baseColor =
      normalizeHexColor(baseStyle.color) ||
      (sel === "income" ? "#22C55E" : "#EF4444");
    const icon =
      newCatIconSelect?.value || detectEmojiByText(name, sel, baseStyle.icon);
    if (icon !== baseStyle.icon) {
      categoryCustomizations[name] = { icon, color: baseColor };
    }
    saveAll();
    renderCategories();
    closeModal("addCatModal");
    showToast(t("saved"));
  });
}
function renderCategories() {
  let html = `<div class="section-hint">💡 ${t("catHint")}</div><button class="cat-unified-add-btn" id="addCatUnifiedBtn"><span class="cat-unified-icon">✚</span><div><div class="cat-unified-title">${t("addCatModalTitle")}</div></div></button><div class="cat-section"><div class="cat-section-header"><div class="cat-section-title">${t("expCatsTitle")}</div></div><div id="categoriesList"></div></div><div class="cat-section"><div class="cat-section-header"><div class="cat-section-title">${t("incomeCats")}</div></div><div id="incomeList"></div></div>`;
  document.getElementById("mainContent").innerHTML = html;
  document
    .getElementById("addCatUnifiedBtn")
    .addEventListener("click", () => openAddCategoryModal("expense"));
  function buildCatList(container, catObj, isIncome) {
    container.innerHTML = "";
    for (const [cat, data] of Object.entries(catObj)) {
      const div = document.createElement("div");
      div.className = "cat-item";
      const safeId =
        "chips-" + (isIncome ? "inc-" : "") + cat.replace(/\s/g, "_");
      const typeKey = isIncome ? "income" : "expense";
      const palette = getCategoryUiPalette(cat, typeKey);
      const style = palette.style;
      if (palette.hasCustomColor) {
        div.style.borderLeft = `4px solid ${palette.edgeColor}`;
        div.style.background = `linear-gradient(135deg, ${palette.surfaceTone} 0%, var(--card-bg) 58%)`;
      } else {
        div.style.borderLeft = `4px solid var(--cream-border)`;
        div.style.background = "";
      }
      div.innerHTML = `<div class="cat-item-header"><div class="cat-item-name" style="display:flex;align-items:center;gap:10px;"><span style="width:34px;height:34px;border-radius:12px;background:${palette.iconTone};border:1px solid ${palette.borderTone};display:inline-flex;align-items:center;justify-content:center;flex:0 0 auto;">${style.icon}</span><span style="color:${palette.titleColor};font-weight:800;">${esc(cat)}</span></div><button class="icon-btn delete" data-delcat="${esc(cat)}">✕</button></div><div class="chips-row" id="${safeId}"></div><button class="cat-add-sub-btn add-sub" data-cat="${esc(cat)}">＋ ${t("addSubcategory")}</button>`;
      container.appendChild(div);
      const chips = document.getElementById(safeId);
      data.subcats.forEach((sub) => {
        const chip = document.createElement("span");
        chip.className = "chip";
        chip.style.background = palette.hasCustomColor
          ? hexToRgba(
              palette.accentColor,
              document.body.classList.contains("dark") ? 0.16 : 0.1,
            )
          : document.body.classList.contains("dark")
            ? "rgba(255,255,255,0.06)"
            : "rgba(255,255,255,0.78)";
        chip.style.border = `1px solid ${
          palette.hasCustomColor
            ? hexToRgba(
                palette.accentColor,
                document.body.classList.contains("dark") ? 0.34 : 0.22,
              )
            : "var(--cream-border)"
        }`;
        const displaySub = getDisplaySubcategoryLabel(sub, typeKey);
        chip.innerHTML = `<span style="color:${palette.subColor};font-weight:800;">${esc(
          displaySub,
        )}</span> <button class="chip-del" data-cat="${esc(cat)}" data-sub="${esc(sub)}">✕</button>`;
        chip.addEventListener("click", (e) => {
          if (e.target.classList.contains("chip-del")) return;
          openSubcategoryEditorModal({
            title: t("editSubcatTitle"),
            parentCategory: cat,
            parentType: typeKey,
            initialValue: sub,
            categoryColor: palette.accentColor,
            onSave: (nextValue) => {
              if (!nextValue.trim()) return;
              const i = catObj[cat].subcats.indexOf(sub);
              if (i === -1) return;
              if (
                nextValue !== sub &&
                catObj[cat].subcats.includes(nextValue)
              ) {
                showToast(t("alreadyExists"), "error");
                return;
              }
              catObj[cat].subcats[i] = nextValue;
              saveAll();
              renderCategories();
            },
          });
        });
        chip.querySelector(".chip-del").addEventListener("click", (e) => {
          e.stopPropagation();
          askConfirm(
            `${t("delete")}: «${sub}»?`,
            () => {
              catObj[cat].subcats = catObj[cat].subcats.filter(
                (s) => s !== sub,
              );
              saveAll();
              renderCategories();
            },
            { icon: "🗑️" },
          );
        });
        chips.appendChild(chip);
      });
      div
        .querySelector(".cat-item-name")
        .addEventListener("click", () => openEditCategoryModal(cat, isIncome));
      div.querySelector("[data-delcat]").addEventListener("click", () => {
        askConfirm(
          `${t("delete")}: «${cat}»?`,
          () => {
            delete catObj[cat];
            saveAll();
            renderCategories();
          },
          { icon: "🗑️" },
        );
      });
      div.querySelector(".add-sub").addEventListener("click", () => {
        openSubcategoryEditorModal({
          title: t("newSubcatTitle"),
          parentCategory: cat,
          parentType: typeKey,
          initialValue: "",
          categoryColor: palette.accentColor,
          onSave: (subValue) => {
            if (!subValue.trim()) return;
            if (catObj[cat].subcats.includes(subValue)) {
              showToast(t("alreadyExists"), "error");
              return;
            }
            catObj[cat].subcats.push(subValue.trim());
            saveAll();
            renderCategories();
          },
        });
      });
    }
  }
  buildCatList(document.getElementById("categoriesList"), categories, false);
  buildCatList(document.getElementById("incomeList"), incomeCategories, true);
}

// ============================================================
// НАСТРОЙКИ — расширенные
// ============================================================
function renderProfilesBody() {
  const activeProf = profiles.find((p) => p.id === activeProfileId);
  const currentUserRole = activeProf?.role;
  const isGuest = currentUserRole === "guest";

  if (!profiles.length)
    profiles = [
      {
        id: "default",
        name: "Main profile",
        emoji: "👤",
        color: "#2d6a4f",
        role: "owner",
      },
    ];

  const profilesHtml = profiles
    .map((p) => {
      // Гость видит только свой профиль (роль guest и активный)
      if (isGuest) {
        if (p.role !== "guest" || p.id !== activeProfileId) return "";
      }

      const isActive = p.id === activeProfileId;
      const pRaw = localStorage.getItem(getProfileStorageKey(p.id));
      let pTxCount = 0,
        pBalance = 0;
      if (pRaw) {
        try {
          const pd = JSON.parse(pRaw);
          pTxCount = (pd.transactions || []).length;
          const inc = (pd.transactions || [])
            .filter((t) => t.type === "income")
            .reduce((s, t) => s + t.amountRub, 0);
          const exp = (pd.transactions || [])
            .filter((t) => t.type === "expense")
            .reduce((s, t) => s + t.amountRub, 0);
          pBalance = inc - exp;
        } catch (e) {}
      } else if (isActive) {
        let inc = 0,
          exp = 0;
        transactions.forEach((t) => {
          if (t.type === "income") inc += t.amountRub;
          else exp += t.amountRub;
        });
        pBalance = inc - exp;
        pTxCount = transactions.length;
      }
      const accentColor = p.color || "#2d6a4f";

      let buttonsHtml = "";
      if (currentUserRole === "owner" || currentUserRole === "user") {
        buttonsHtml = `
          ${!isActive && !isGuest ? `<button class="icon-btn edit" data-switchpid="${p.id}" style="width:34px;height:34px;font-size:14px;" title="${t("profileSwitch")}">▶</button>` : ""}
          <button class="icon-btn edit" data-renamepid="${p.id}" style="width:34px;height:34px;font-size:14px;" title="${t("profileRename")}">✏️</button>
          <button class="icon-btn edit" data-sharepid="${p.id}" style="width:34px;height:34px;font-size:14px;background:var(--primary-pale);color:var(--primary);" title="${t("shareTitle")}">🔗</button>
          ${profiles.length > 1 && p.id !== "default" ? `<button class="icon-btn delete" data-deletepid="${p.id}" style="width:34px;height:34px;font-size:14px;" title="${t("profileDelete")}">🗑</button>` : ""}
        `;
      } else if (currentUserRole === "guest") {
        if (isActive) {
          buttonsHtml = `<button class="icon-btn edit" data-renamepid="${p.id}" style="width:34px;height:34px;font-size:14px;" title="${t("profileRename")}">✏️</button>`;
        }
      }

      return `<div style="display:flex;align-items:center;gap:12px;padding:12px;margin-bottom:8px;background:${
        isActive
          ? "color-mix(in srgb, var(--primary-pale) 60%, var(--settings-surface-strong, var(--card-bg)))"
          : "var(--settings-surface-strong, var(--cream-dark))"
      };border-radius:16px;border:1.5px solid ${
        isActive
          ? "color-mix(in srgb, var(--primary) 42%, var(--settings-border-strong, var(--cream-border)))"
          : "var(--settings-border, var(--cream-border))"
      };box-shadow:var(--settings-shadow-soft, var(--shadow-sm));">
      <div style="width:44px;height:44px;border-radius:50%;background:${accentColor};display:flex;align-items:center;justify-content:center;font-size:22px;flex-shrink:0;">${
        p.emoji || "👤"
      }</div>
      <div style="flex:1;min-width:0;">
        <div style="font-size:15px;font-weight:800;color:var(--text);">${esc(p.name)}${
          isActive
            ? ` <span style="font-size:11px;font-weight:700;color:var(--primary);background:color-mix(in srgb, var(--primary-pale) 72%, var(--settings-surface-strong, var(--card-bg)));padding:2px 8px;border-radius:99px;border:1px solid color-mix(in srgb, var(--primary) 18%, var(--settings-border, var(--cream-border)));">${t("profileActive")}</span>`
            : ""
        }</div>
        <div style="font-size:12px;color:var(--text-muted);margin-top:2px;">${pTxCount} ${t("statsRec")} · ${fmt(pBalance)}</div>
      </div>
      <div style="display:flex;gap:6px;flex-shrink:0;">${buttonsHtml}</div>
    </div>`;
    })
    .join("");

  // Кнопки выхода / возврата только для владельца
  const isOwnerInGuestMode =
    activeProf?.role === "owner" && activeProf?.isShared === true;
  const isOwnerInOtherProfile =
    currentUserRole === "owner" &&
    activeProf?.id !== "default" &&
    !activeProf?.isShared;

  let actionBtn = "";
  if (isOwnerInGuestMode) {
    actionBtn = `
      <div style="margin-top:16px; padding-top:16px; border-top:1px solid var(--cream-border);">
        <button class="btn-primary" id="exitGuestModeBtn" style="width:100%; background:var(--expense-color);">🚪 ${t("exitGuestMode")}</button>
      </div>
    `;
  } else if (isOwnerInOtherProfile) {
    actionBtn = `
      <div style="margin-top:16px; padding-top:16px; border-top:1px solid var(--cream-border);">
        <button class="btn-primary" id="backToMainProfileBtn" style="width:100%; background:var(--gold);">👑 Вернуться в главный профиль</button>
      </div>
    `;
  }

  return profilesHtml + actionBtn;
}

// ============================================================
// БИОМЕТРИЯ (WebAuthn)
// ============================================================
function getNativeBiometryPlugin() {
  const plugins = window.Capacitor?.Plugins || {};
  return (
    plugins.NativeBiometric ||
    plugins.BiometricAuth ||
    plugins.CapacitorBiometrics ||
    null
  );
}

async function nativeBiometryVerify(options = {}) {
  const plugin = getNativeBiometryPlugin();
  if (!plugin) return false;
  const nativeBiometryOptions = {
    reason: t("biometryToggleLabel") || "Login with biometry",
    title: t("biometryTitle") || "Biometry",
    subtitle: t("biometryDesc") || "Fingerprint / Face ID",
    description: t("biometryDesc") || "Fingerprint / Face ID",
    negativeButtonText: t("cancel") || "Cancel",
    maxAttempts: 5,
    allowedBiometryTypes: [3, 4, 5, 6],
  };
  try {
    if (typeof plugin.verifyIdentity === "function") {
      const result = await plugin.verifyIdentity(nativeBiometryOptions);
      return result?.verified !== false;
    }
    if (typeof plugin.authenticate === "function") {
      const result = await plugin.authenticate(nativeBiometryOptions);
      return result?.success !== false && result?.authenticated !== false;
    }
  } catch (e) {
    console.warn("native biometry verify:", e);
  }
  return false;
}

async function isBiometryAvailable() {
  try {
    const plugin = getNativeBiometryPlugin();
    if (plugin?.isAvailable) {
      const result = await plugin.isAvailable();
      if (result?.isAvailable || result?.available || result?.biometryType)
        return true;
    }
    if (
      window.PublicKeyCredential?.isUserVerifyingPlatformAuthenticatorAvailable
    ) {
      return await PublicKeyCredential.isUserVerifyingPlatformAuthenticatorAvailable();
    }
  } catch (e) {
    console.warn("biometry available:", e);
  }
  return false;
}

async function biometryRegister() {
  try {
    if (await nativeBiometryVerify()) {
      biometryCredId = "native";
      biometryEnabled = true;
      saveAll();
      return true;
    }
    const challenge = crypto.getRandomValues(new Uint8Array(32));
    const cred = await navigator.credentials.create({
      publicKey: {
        challenge,
        rp: { name: "БюджетPRO" },
        user: {
          id: crypto.getRandomValues(new Uint8Array(16)),
          name: "user",
          displayName: "Пользователь",
        },
        pubKeyCredParams: [
          { type: "public-key", alg: -7 },
          { type: "public-key", alg: -257 },
        ],
        authenticatorSelection: {
          authenticatorAttachment: "platform",
          userVerification: "required",
        },
        timeout: 60000,
      },
    });
    if (!cred) return null;
    biometryCredId = btoa(String.fromCharCode(...new Uint8Array(cred.rawId)));
    biometryEnabled = true;
    saveAll();
    return true;
  } catch (e) {
    console.warn("biometry register:", e);
    return null;
  }
}

async function biometryVerify() {
  if (!biometryCredId) return false;
  if (biometryCredId === "native") return nativeBiometryVerify();
  const nativeOk = await nativeBiometryVerify();
  if (nativeOk) return true;
  try {
    const challenge = crypto.getRandomValues(new Uint8Array(32));
    const rawId = Uint8Array.from(atob(biometryCredId), (c2) =>
      c2.charCodeAt(0),
    );
    const assertion = await navigator.credentials.get({
      publicKey: {
        challenge,
        allowCredentials: [{ type: "public-key", id: rawId }],
        userVerification: "required",
        timeout: 60000,
      },
    });
    return !!assertion;
  } catch (e) {
    console.warn("biometry verify:", e);
    return false;
  }
}

// ============================================================
// ПИН-КОД
// ============================================================
async function hashPin(pin) {
  const data = new TextEncoder().encode(pin + "budget_salt_2024");
  const buf = await crypto.subtle.digest("SHA-256", data);
  return Array.from(new Uint8Array(buf))
    .map((b) => b.toString(16).padStart(2, "0"))
    .join("");
}

function openEditTemplateModal(tplIdx) {
  const tpl = userTemplates[tplIdx];
  if (!tpl) return;
  const iType = tpl.type || "expense";
  const cats =
    iType === "expense"
      ? Object.keys(categories)
      : Object.keys(incomeCategories);
  const html = `
    <div class="field-group"><label class="field-label">${t("type")}</label>
      <div class="type-toggle">
        <button class="type-btn expense${iType === "expense" ? " active" : ""}" data-type="expense">${t("expenseType")}</button>
        <button class="type-btn income${iType === "income" ? " active" : ""}" data-type="income">${t("incomeType")}</button>
      </div></div>
    <div class="field-group"><label class="field-label">${t("category")}</label>
      <select id="etCat" class="modal-select">
        ${cats.map((c2) => `<option value="${c2}"${c2 === tpl.category ? " selected" : ""}>${c2}</option>`).join("")}
      </select></div>
    <div class="field-group"><label class="field-label">${t("amount")} (${sym()})</label>
      <input type="number" id="etAmt" class="modal-input" value="${toDisp(tpl.amountRub || 0).toFixed(2)}" min="0.01" step="any"></div>
    <div class="field-group"><label class="field-label">${t("note")}</label>
      <input type="text" id="etNote" class="modal-input" value="${esc(tpl.note || "")}"></div>
    <div class="modal-actions">
      <button class="btn-secondary" id="etCancel">${t("cancel")}</button>
      <button class="btn-primary" id="etSave">💾 ${t("save")}</button>
    </div>`;
  const modal = createModal("etModal", t("edit"), html);
  document.body.appendChild(modal);
  openModal("etModal");
  let curType = iType;
  modal.querySelectorAll(".type-btn").forEach((btn) => {
    btn.addEventListener("click", () => {
      curType = btn.dataset.type;
      modal
        .querySelectorAll(".type-btn")
        .forEach((b) => b.classList.remove("active"));
      btn.classList.add("active");
      const newCats =
        curType === "expense"
          ? Object.keys(categories)
          : Object.keys(incomeCategories);
      document.getElementById("etCat").innerHTML = newCats
        .map((c2) => `<option value="${c2}">${c2}</option>`)
        .join("");
    });
  });
  document
    .getElementById("etCancel")
    ?.addEventListener("click", () => closeModal("etModal"));
  document.getElementById("etSave")?.addEventListener("click", () => {
    const amt = parseFloat(document.getElementById("etAmt").value);
    const cat = document.getElementById("etCat").value;
    if (!cat || isNaN(amt) || amt <= 0) {
      showToast(t("enterPositive"), "error");
      return;
    }
    tpl.type = curType;
    tpl.category = cat;
    tpl.amountRub = toRub(amt);
    tpl.note = document.getElementById("etNote").value.trim();
    tpl.name = cat + " " + toDisp(tpl.amountRub).toFixed(0) + " " + sym();
    saveAll();
    closeModal("etModal");
    renderSettings();
    showToast(t("saved"));
    haptic("success");
  });
}

