function isReminderWeekdayAllowed(ts) {
  if (!Array.isArray(reminderWeekdays) || !reminderWeekdays.length) return true;
  return reminderWeekdays.includes(new Date(ts).getDay());
}

function getReminderNotificationId(seed) {
  const numeric = String(seed || Date.now()).replace(/\D/g, "");
  return Number(numeric.slice(-8) || Date.now().toString().slice(-8));
}

async function ensureReminderNotificationChannel() {
  const plugin = getLocalNotificationsPlugin();
  if (!plugin?.createChannel) return;
  try {
    await plugin.createChannel({
      id: "budget-reminders",
      name: "BudgetPRO Reminders",
      description:
        "Full reminder notifications from BudgetPRO with scheduled text and emoji.",
      importance: 5,
      visibility: 1,
      vibration: true,
      lights: true,
    });
  } catch (e) {}
}

async function getReminderPermissionState() {
  const plugin = getLocalNotificationsPlugin();
  if (plugin?.checkPermissions) {
    try {
      const perm = await plugin.checkPermissions();
      const state = perm.display || perm.schedule || "prompt";
      localStorage.setItem("nativeReminderPermission", state);
      return state;
    } catch (e) {}
  }
  if (typeof Notification !== "undefined") return Notification.permission;
  return "denied";
}

async function requestReminderPermission() {
  const plugin = getLocalNotificationsPlugin();
  if (plugin?.requestPermissions) {
    const perm = await plugin.requestPermissions();
    const state = perm.display || perm.schedule || "prompt";
    localStorage.setItem("nativeReminderPermission", state);
    return state;
  }
  if (typeof Notification !== "undefined") {
    return Notification.requestPermission();
  }
  return "denied";
}

async function cancelNativeReminderNotificationById(id) {
  const bridge = getNativeNotificationsBridge();
  if (bridge && id) {
    try {
      if (typeof bridge.cancelExactReminder === "function") {
        bridge.cancelExactReminder(Number(id));
      }
    } catch (e) {}
  }
  const plugin = getLocalNotificationsPlugin();
  if (!plugin?.cancel || !id) return;
  try {
    await plugin.cancel({ notifications: [{ id }] });
  } catch (e) {}
}

function getTrackedNativeNamedReminderIds() {
  try {
    return JSON.parse(
      localStorage.getItem("nativeExactNamedIds") || "[]",
    ).filter(Boolean);
  } catch (e) {
    return [];
  }
}

function setTrackedNativeNamedReminderIds(ids) {
  localStorage.setItem(
    "nativeExactNamedIds",
    JSON.stringify([
      ...new Set((ids || []).map((id) => Number(id)).filter(Boolean)),
    ]),
  );
}

function trackNativeNamedReminderId(id) {
  const ids = getTrackedNativeNamedReminderIds();
  ids.push(Number(id));
  setTrackedNativeNamedReminderIds(ids);
}

function untrackNativeNamedReminderId(id) {
  setTrackedNativeNamedReminderIds(
    getTrackedNativeNamedReminderIds().filter((x) => Number(x) !== Number(id)),
  );
}

async function cleanupStaleNativeNamedReminderNotifications() {
  const bridge = getNativeNotificationsBridge();
  const plugin = getLocalNotificationsPlugin();
  const trackedIds = getTrackedNativeNamedReminderIds();
  if (!bridge) return;
  const activeIdList = JSON.parse(
    localStorage.getItem("namedReminders") || "[]",
  )
    .map((r) => Number(r.notificationId))
    .filter(Boolean);
  const activeIds = new Set(
    JSON.parse(localStorage.getItem("namedReminders") || "[]")
      .map((r) => Number(r.notificationId))
      .filter(Boolean),
  );
  try {
    if (typeof bridge.clearTrackedExactRemindersExcept === "function") {
      bridge.clearTrackedExactRemindersExcept(JSON.stringify(activeIdList));
    }
  } catch (e) {}
  if (plugin?.getPending && plugin?.cancel) {
    try {
      const pending = await plugin.getPending();
      const stalePluginIds = (pending.notifications || [])
        .filter((n) => {
          const id = Number(n.id);
          const isRecurring =
            n.extra?.reminderType === "recurring" || id >= 810000;
          if (isRecurring) return false;
          if (!activeIdList.length) return true;
          return !activeIds.has(id);
        })
        .map((n) => ({ id: n.id }));
      if (stalePluginIds.length) {
        await plugin.cancel({ notifications: stalePluginIds });
      }
    } catch (e) {}
  }
  if (
    plugin?.getDeliveredNotifications &&
    plugin?.removeDeliveredNotifications &&
    !activeIdList.length
  ) {
    try {
      const delivered = await plugin.getDeliveredNotifications();
      const staleDeliveredIds = (delivered.notifications || [])
        .filter((n) => {
          const id = Number(n.id);
          return !(n.extra?.reminderType === "recurring" || id >= 810000);
        })
        .map((n) => ({ id: n.id }));
      if (staleDeliveredIds.length) {
        await plugin.removeDeliveredNotifications({
          notifications: staleDeliveredIds,
        });
      }
    } catch (e) {}
  }
  if (!trackedIds.length) return;
  const staleIds = trackedIds.filter((id) => !activeIds.has(Number(id)));
  for (const id of staleIds) {
    try {
      if (typeof bridge.cancelExactReminder === "function") {
        bridge.cancelExactReminder(Number(id));
      }
    } catch (e) {}
  }
  setTrackedNativeNamedReminderIds(
    trackedIds.filter((id) => activeIds.has(Number(id))),
  );
}

function getSavedRecurringReminderDeliveryMode() {
  return (
    localStorage.getItem("customRecurringReminderDeliveryMode") ||
    "sound_vibration"
  );
}

function getSavedRecurringReminderSoundChoice() {
  return localStorage.getItem("customRecurringReminderSoundChoice") || "";
}

function getRecurringExactAlarmHorizonCount(interval) {
  const map = {
    "1min": 90,
    "5min": 72,
    "10min": 60,
    "15min": 48,
    "30min": 36,
    "1h": 24,
    "2h": 18,
    "5h": 12,
    daily: 14,
    every3days: 10,
    weekly: 8,
  };
  return map[interval] || 60;
}

async function syncExactAlarmRecurringReminderNotifications() {
  const bridge = getNativeNotificationsBridge();
  if (!bridge) return;
  const baseId = 910000;
  const legacyPluginBaseId = 810000;
  const oldIds = JSON.parse(
    localStorage.getItem("nativeExactRecurringIds") || "[]",
  );
  const allPossibleIds = [];
  for (let intervalIdx = 0; intervalIdx < 12; intervalIdx++) {
    for (let slot = 0; slot < 120; slot++) {
      allPossibleIds.push(baseId + intervalIdx * 2000 + slot);
    }
  }
  for (const id of [...new Set([...oldIds, ...allPossibleIds])]) {
    try {
      bridge.cancelExactReminder(Number(id));
    } catch (e) {}
  }
  const plugin = getLocalNotificationsPlugin();
  if (plugin?.getPending && plugin?.cancel) {
    try {
      const pending = await plugin.getPending();
      const legacyRecurringIds = (pending.notifications || [])
        .filter(
          (n) =>
            n.id >= legacyPluginBaseId || n.extra?.reminderType === "recurring",
        )
        .map((n) => ({ id: n.id }));
      if (legacyRecurringIds.length) {
        await plugin.cancel({ notifications: legacyRecurringIds });
      }
    } catch (e) {}
  }

  const now = Date.now();
  const scheduledIds = [];
  const activeIntervals = Object.entries(reminderIntervals || {}).filter(
    ([, active]) => !!active,
  );

  for (const [idx, [interval]] of activeIntervals.entries()) {
    const step = getIntervalMs(interval);
    if (!step) continue;
    let cursor = now + step;
    let slot = 0;
    const maxCount = getRecurringExactAlarmHorizonCount(interval);
    while (slot < maxCount) {
      if (!isReminderWeekdayAllowed(cursor)) {
        cursor += step;
        continue;
      }
      const notificationId = baseId + idx * 2000 + slot;
      let ok = false;
      try {
        if (typeof bridge.scheduleExactReminderDetailed === "function") {
          ok = bridge.scheduleExactReminderDetailed(
            cursor,
            notificationId,
            getRecurringReminderTitle(interval),
            getRecurringReminderBody(interval),
            getSavedRecurringReminderDeliveryMode(),
            getSavedRecurringReminderSoundChoice(),
          );
        } else if (typeof bridge.scheduleExactReminder === "function") {
          ok = bridge.scheduleExactReminder(
            cursor,
            notificationId,
            getRecurringReminderTitle(interval),
            getRecurringReminderBody(interval),
          );
        }
      } catch (e) {}
      if (ok) scheduledIds.push(notificationId);
      cursor += step;
      slot++;
    }
  }

  localStorage.setItem("nativeExactRecurringIds", JSON.stringify(scheduledIds));
}

async function scheduleNativeNamedReminder(r) {
  const bridge = getNativeNotificationsBridge();
  if (bridge) {
    const ts = Number(r.ts);
    if (!ts || ts <= Date.now()) return false;
    const notificationId = r.notificationId || getReminderNotificationId(r.id);
    try {
      if (typeof bridge.scheduleExactReminderDetailed === "function") {
        const ok = !!bridge.scheduleExactReminderDetailed(
          ts,
          notificationId,
          getReminderNotificationTitle(r.name),
          r.body || getReminderNotificationBody(r.name),
          r.deliveryMode || "sound_vibration",
          r.soundChoice || "",
        );
        if (ok) trackNativeNamedReminderId(notificationId);
        return ok;
      }
      if (typeof bridge.scheduleExactReminder === "function") {
        const ok = !!bridge.scheduleExactReminder(
          ts,
          notificationId,
          getReminderNotificationTitle(r.name),
          r.body || getReminderNotificationBody(r.name),
        );
        if (ok) trackNativeNamedReminderId(notificationId);
        return ok;
      }
      return false;
    } catch (e) {
      return false;
    }
  }
  const plugin = getLocalNotificationsPlugin();
  if (!plugin?.schedule) return false;
  const at = new Date(r.ts);
  if (
    !(at instanceof Date) ||
    Number.isNaN(at.getTime()) ||
    at.getTime() <= Date.now()
  ) {
    return false;
  }
  await ensureReminderNotificationChannel();
  try {
    await plugin.schedule({
      notifications: [
        {
          id: r.notificationId || getReminderNotificationId(r.id),
          title: getReminderNotificationTitle(r.name),
          body: r.body || getReminderNotificationBody(r.name),
          schedule: { at, allowWhileIdle: true },
          channelId: "budget-reminders",
          ongoing: false,
          autoCancel: true,
          smallIcon: "ic_launcher_foreground",
          extra: { reminderId: r.id, reminderType: "named" },
        },
      ],
    });
    return true;
  } catch (e) {
    return false;
  }
}

async function syncNativeRecurringReminderNotifications() {
  if (canUseExactReminderBridge()) {
    await syncExactAlarmRecurringReminderNotifications();
    return;
  }
  const plugin = getLocalNotificationsPlugin();
  if (!plugin?.schedule) return;
  await ensureReminderNotificationChannel();
  const notifications = [];
  const now = Date.now();
  const horizonMs = 30 * 24 * 60 * 60 * 1000;
  const baseId = 810000;
  const activeIntervals = Object.entries(reminderIntervals || {}).filter(
    ([, active]) => !!active,
  );

  for (const [idx, [interval]] of activeIntervals.entries()) {
    const step = getIntervalMs(interval);
    if (!step) continue;
    let cursor = now + step;
    let slot = 0;
    while (cursor <= now + horizonMs && slot < 400) {
      if (!isReminderWeekdayAllowed(cursor)) {
        cursor += step;
        continue;
      }
      notifications.push({
        id: baseId + idx * 500 + slot,
        title: getRecurringReminderTitle(interval),
        body: getRecurringReminderBody(interval),
        schedule: { at: new Date(cursor), allowWhileIdle: true },
        channelId: "budget-reminders",
        ongoing: false,
        autoCancel: true,
        smallIcon: "ic_launcher_foreground",
        extra: { reminderType: "recurring", interval },
      });
      cursor += step;
      slot++;
    }
  }

  try {
    const pending = await plugin.getPending();
    const recurringIds = (pending.notifications || [])
      .filter((n) => n.extra?.reminderType === "recurring" || n.id >= baseId)
      .map((n) => ({ id: n.id }));
    if (recurringIds.length) {
      await plugin.cancel({ notifications: recurringIds });
    }
  } catch (e) {}

  if (notifications.length) {
    try {
      await plugin.schedule({ notifications });
    } catch (e) {}
  }
}

async function syncNativeNamedReminderNotifications() {
  const list = JSON.parse(localStorage.getItem("namedReminders") || "[]");
  for (const r of list) {
    if (r.fired || !r.ts || r.ts <= Date.now()) continue;
    r.notificationId = r.notificationId || getReminderNotificationId(r.id);
    await scheduleNativeNamedReminder(r);
  }
  localStorage.setItem("namedReminders", JSON.stringify(list));
}

async function reconcileNativeReminderAlarms() {
  if (!isNativeReminderRuntime()) return;
  const named = JSON.parse(localStorage.getItem("namedReminders") || "[]");
  const hasNamed = named.some((r) => !r.fired && Number(r.ts) > Date.now());
  const hasRecurring = hasActiveRecurringReminderIntervals();
  if (!hasNamed && !hasRecurring) {
    clearRecurringReminderState();
    setTrackedNativeNamedReminderIds([]);
  }
  await cleanupStaleNativeNamedReminderNotifications();
  await syncNativeRecurringReminderNotifications();
}

// ── Schedule a named reminder with setTimeout (best-effort) ──
function scheduleNamedReminder(r) {
  if (isNativeReminderRuntime()) return;
  const delay = r.tsMs - Date.now();
  if (delay <= 0 || delay > 7 * 24 * 3600 * 1000) return; // skip if past or >7 days
  setTimeout(() => {
    const list = JSON.parse(localStorage.getItem("namedReminders") || "[]");
    const item = list.find((x) => x.id === r.id);
    if (!item || item.fired) return;
    fireNamedReminder(item);
    item.fired = true;
    localStorage.setItem("namedReminders", JSON.stringify(list));
    if (currentTab === "settings") renderSettings();
  }, delay);
}

function fireNamedReminder(r) {
  const body = getReminderNotificationBody(r.name);

  // Надёжное локальное уведомление (липучее, с вибрацией и звуком)
  showStickyNotification(
    getReminderNotificationTitle(r.name),
    body,
    "named-" + r.id,
  );

  showToast("🔔 " + body, "success", 5000);
  if (typeof haptic === "function") haptic("medium");
}

// Re-schedule any pending named reminders on page load
function rescheduleNamedReminders() {
  if (isNativeReminderRuntime()) {
    syncNativeNamedReminderNotifications();
    return;
  }
  const list = JSON.parse(localStorage.getItem("namedReminders") || "[]");
  const now = Date.now();
  let changed = false;
  list.forEach((r) => {
    if (!r.fired) {
      if (r.ts <= now) {
        // Missed while page was closed - fire now
        fireNamedReminder(r);
        r.fired = true;
        changed = true;
      } else {
        scheduleNamedReminder(r);
      }
    }
  });
  if (changed) localStorage.setItem("namedReminders", JSON.stringify(list));
}
setTimeout(rescheduleNamedReminders, 1000);

function sendReminderNotification() {
  if (isNativeReminderRuntime()) return;
  if (typeof Notification === "undefined") return;
  const canNotify = Notification.permission === "granted";
  const now = Date.now();

  // ── Проверка именованных напоминаний ──
  const list = JSON.parse(localStorage.getItem("namedReminders") || "[]");
  let changed = false;
  list.forEach((r) => {
    if (!r.fired && r.ts <= now) {
      fireNamedReminder(r); // fireNamedReminder теперь сама вызывает showStickyNotification
      r.fired = true;
      changed = true;
    }
  });
  if (changed) {
    localStorage.setItem("namedReminders", JSON.stringify(list));
    if (currentTab === "settings") renderSettings();
  }

  // ── Проверка интервальных напоминаний ──
  if (!remindersEnabled || !canNotify) return;
  for (const [interval, active] of Object.entries(reminderIntervals)) {
    if (!active) continue;
    const lastKey = `lastReminder_${interval}`;
    const last = localStorage.getItem(lastKey);
    const ms = getIntervalMs(interval);
    const should = !last || now - parseInt(last) >= ms;
    if (should && isReminderWeekdayAllowed(now)) {
      showStickyNotification(
        getRecurringReminderTitle(interval),
        getRecurringReminderBody(interval),
        "budget-reminder",
      );
      localStorage.setItem(lastKey, now);
    }
  }
}

// Подписка на push-уведомления (вызывается при инициализации)
async function subscribeUserToPush() {
  if (!("serviceWorker" in navigator) || !("PushManager" in window)) {
    console.warn("❌ Push-уведомления не поддерживаются");
    return null;
  }

  if (!VAPID_PUBLIC_KEY) {
    console.warn("❌ VAPID public key is not configured");
    return null;
  }

  try {
    const registration = await navigator.serviceWorker.ready;
    let subscription = await registration.pushManager.getSubscription();

    if (!subscription) {
      subscription = await registration.pushManager.subscribe({
        userVisibleOnly: true,
        applicationServerKey: urlBase64ToUint8Array(VAPID_PUBLIC_KEY),
      });
    }

    // Сохраняем подписку в localStorage, чтобы потом использовать при отправке
    localStorage.setItem("pushSubscription", JSON.stringify(subscription));
    console.log("✅ Пользователь подписан на push");
    return subscription;
  } catch (e) {
    console.warn("❌ Ошибка подписки на push:", e);
    return null;
  }
}

// Отправляет push через нашу облачную функцию (сервер)
async function sendPushViaServer(title, body, tag, vibrate) {
  const sub = JSON.parse(localStorage.getItem("pushSubscription"));
  if (!sub || !sub.endpoint) {
    console.warn("❌ Нет подписки");
    return false;
  }

  try {
    const response = await fetch(
      "https://military-apple.surge.sh/.netlify/functions/sendPush",
      {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          subscription: sub,
          title: title,
          body: body,
          tag: tag || "budget-reminder",
          vibrate: vibrate || [200, 100, 200, 100, 200],
        }),
      },
    );
    if (response.ok) {
      console.log("📤 Push отправлен через сервер");
      return true;
    }
    return false;
  } catch (e) {
    console.warn("❌ Ошибка отправки push через сервер:", e);
    return false;
  }
}

// Универсальная функция для показа уведомлений (липкие, с вибрацией)
function showStickyNotification(title, body, tag) {
  const soundEnabled = localStorage.getItem("reminderSoundEnabled") !== "false";
  const vibrate = soundEnabled ? [200, 100, 200, 100, 200] : undefined;

  const options = {
    body: body,
    icon: "/favicon-96x96.png",
    tag: tag || "budget-reminder",
    requireInteraction: true,
    vibrate: vibrate,
    silent: !soundEnabled,
  };

  if ("serviceWorker" in navigator && navigator.serviceWorker.controller) {
    navigator.serviceWorker.ready.then((reg) =>
      reg.showNotification(title, options),
    );
  } else if (Notification.permission === "granted") {
    new Notification(title, options);
  }
}

// Poll every 60 seconds — works even when setTimeout is killed on mobile background
let _globalReminderPoller = null;
function startReminderPoller() {
  if (_globalReminderPoller) return; // already running
  _globalReminderPoller = setInterval(sendReminderNotification, 60 * 1000);
  // Also check immediately
  setTimeout(sendReminderNotification, 500);
}

function startReminderTimer() {
  if (reminderTimer) clearInterval(reminderTimer);
  if (!remindersEnabled) return;
  // Legacy: keep for compatibility — main polling is in startReminderPoller
  reminderTimer = setInterval(sendReminderNotification, 5 * 60 * 1000);
  sendReminderNotification();
}
function stopReminderTimer() {
  if (reminderTimer) {
    clearInterval(reminderTimer);
    reminderTimer = null;
  }
}
function saveReminderSettings() {
  localStorage.setItem("remindersEnabled", remindersEnabled);
  localStorage.setItem("remindersInterval", remindersInterval);
}
function loadReminderSettings() {
  remindersEnabled = localStorage.getItem("remindersEnabled") === "true";
  const si = localStorage.getItem("remindersInterval");
  if (si && ["daily", "every3days", "weekly"].includes(si))
    remindersInterval = si;
  if (isNativeReminderRuntime()) {
    getReminderPermissionState().then(() => {
      syncNativeNamedReminderNotifications();
      reconcileNativeReminderAlarms();
    });
    return;
  }
  if (remindersEnabled) startReminderTimer();
}

// ============================================================
// СПРАВКА И ГАЙ
// ============================================================
function showHelpModal() {
  const modal = createModal(
    "helpModal",
    t("helpTitle"),
    `<div style="max-height:70vh;overflow-y:auto;">${t("helpContent")}</div>`,
  );
  document.body.appendChild(modal);
  openModal("helpModal");
}

// ============================================================
// ВСПОМОГАТЕЛЬНЫЕ
// ============================================================
function openInputModal(title, label, defVal, onSave) {
  const html = `<div class="field-group"><label class="field-label">${esc(label)}</label><input type="text" id="inputModalVal" class="modal-input" value="${esc(defVal)}" autofocus></div><div class="modal-actions"><button class="btn-secondary" id="imCancel">${t("cancel")}</button><button class="btn-primary" id="imSave">${t("save")}</button></div>`;
  const modal = createModal("inputModal", title, html);
  document.body.appendChild(modal);
  openModal("inputModal");
  setTimeout(() => document.getElementById("inputModalVal")?.focus(), 300);
  document.getElementById("imSave").addEventListener("click", () => {
    const v = document.getElementById("inputModalVal").value.trim();
    closeModal("inputModal");
    onSave(v);
  });
  document
    .getElementById("imCancel")
    .addEventListener("click", () => closeModal("inputModal"));
  document.getElementById("inputModalVal").addEventListener("keydown", (e) => {
    if (e.key === "Enter") document.getElementById("imSave").click();
  });
}
function createModal(id, title, bodyHtml) {
  document.getElementById(id)?.remove();
  const ov = document.createElement("div");
  ov.id = id;
  if (id === "addModal") {
    if (!document.getElementById("addModalMotionCSS")) {
      const motionStyle = document.createElement("style");
      motionStyle.id = "addModalMotionCSS";
      motionStyle.textContent = `
        #addModal .add-modal-overlay {
          opacity: 0;
          transition: opacity 320ms ease-out;
        }
        #addModal .add-modal-sheet {
          transform: translateY(0);
          opacity: 0;
          transition: opacity 140ms ease-out;
          will-change: opacity !important;
          backface-visibility: hidden !important;
          transform-origin: bottom center !important;
        }
        #addModal.open .add-modal-overlay {
          opacity: 1 !important;
        }
        #addModal.open .add-modal-sheet {
          transform: translateY(0) !important;
          opacity: 1 !important;
        }
        #addModal.closing .add-modal-overlay {
          opacity: 0 !important;
        }
        #addModal.closing .add-modal-sheet {
          transform: translateY(0) !important;
          opacity: 0 !important;
          transition: opacity 140ms ease-out !important;
        }
        #addModal .add-modal-sheet.dragging {
          transition: none !important;
        }
      `;
      document.head.appendChild(motionStyle);
    }
    ov.className = "add-modal-host";
    ov.style.display = "none";
    ov.innerHTML = `<div class="more-overlay add-modal-overlay"></div><div class="more-sheet add-modal-sheet"><div class="more-handle"></div><div class="modal-header"><h2>${esc(title)}</h2><button class="modal-close">✕</button></div><div class="modal-body">${bodyHtml}</div></div>`;
    const addSheet = ov.querySelector(".add-modal-sheet");
    const addOverlay = ov.querySelector(".add-modal-overlay");
    if (addSheet) {
      addSheet.style.willChange = "opacity";
    }
    if (addOverlay) {
      addOverlay.style.willChange = "opacity";
    }
    ov.querySelector(".modal-close").addEventListener("click", () =>
      closeModal(id),
    );
    ov.querySelector(".add-modal-overlay")?.addEventListener("click", () =>
      closeModal(id),
    );
    const sheet = ov.querySelector(".add-modal-sheet");
    const body = ov.querySelector(".modal-body");
    let startY = 0;
    let currentY = 0;
    let dragging = false;
    let dragIntent = false;

    const onStart = (e) => {
      const point = e.touches?.[0];
      if (!point || !sheet) return;
      const target = e.target;
      const fromCloseBtn = !!target.closest(".modal-close");
      const fromDragZone = !!target.closest(".more-handle, .modal-header");
      if (fromCloseBtn || !fromDragZone) {
        dragIntent = false;
        return;
      }
      startY = point.clientY;
      currentY = 0;
      dragging = false;
      dragIntent = true;
    };

    const onMove = (e) => {
      if (!dragIntent || !sheet) return;
      const point = e.touches?.[0];
      if (!point) return;
      const deltaY = point.clientY - startY;
      if (!dragging) {
        if (deltaY <= 12) return;
        dragging = true;
        sheet.classList.add("dragging");
        sheet.style.transition = "none";
        sheet.style.transform = "translateY(0)";
      }
      currentY = Math.max(0, deltaY);
      if (currentY > 0) {
        e.preventDefault();
        sheet.style.transform = `translateY(${currentY}px)`;
      }
    };

    const onEnd = () => {
      if (!sheet) return;
      const wasDragging = dragging;
      dragging = false;
      dragIntent = false;
      sheet.classList.remove("dragging");
      if (!wasDragging) {
        currentY = 0;
        return;
      }
      if (currentY > 110) {
        closeModal(id);
      } else {
        sheet.style.transition = "transform .22s ease";
        sheet.style.transform = "translateY(0)";
        setTimeout(() => {
          if (sheet) sheet.style.transition = "";
        }, 220);
      }
      currentY = 0;
      dragAllowed = false;
    };

    sheet?.addEventListener("touchstart", onStart, { passive: true });
    sheet?.addEventListener("touchmove", onMove, { passive: false });
    sheet?.addEventListener("touchend", onEnd, { passive: true });
    sheet?.addEventListener("touchcancel", onEnd, { passive: true });
    return ov;
  }
  ov.className = "modal-overlay";
  ov.innerHTML = `<div class="modal"><div class="modal-handle"></div><div class="modal-header"><h2>${esc(title)}</h2><button class="modal-close">✕</button></div><div class="modal-body">${bodyHtml}</div></div>`;
  ov.querySelector(".modal-close").addEventListener("click", () =>
    closeModal(id),
  );
  ov.addEventListener("click", (e) => {
    if (e.target === ov) closeModal(id);
  });
  return ov;
}
function openModal(id) {
  const m = document.getElementById(id);
  if (m) {
    if (id === "addModal") {
      if (
        document.activeElement &&
        typeof document.activeElement.blur === "function"
      ) {
        document.activeElement.blur();
      }
      m.style.display = "block";
      m.classList.remove("closing");
      m.classList.remove("open");
      m.classList.add("opening");
      const sheet = m.querySelector(".add-modal-sheet");
      const modalBody = m.querySelector(".modal-body");
      if (sheet) {
        sheet.classList.remove("dragging");
        sheet.getAnimations?.().forEach((animation) => animation.cancel());
        sheet.style.transition = "";
        sheet.style.transform = "translateY(105%)";
        sheet.style.opacity = "0";
        sheet.style.willChange = "opacity";
        sheet.scrollTop = 0;
      }
      if (modalBody) {
        modalBody.scrollTop = 0;
        if (typeof modalBody.scrollTo === "function") {
          modalBody.scrollTo({ top: 0, behavior: "instant" });
        }
      }
      requestAnimationFrame(() => {
        m.classList.add("open");
        if (modalBody) {
          modalBody.scrollTop = 0;
          if (typeof modalBody.scrollTo === "function") {
            modalBody.scrollTo({ top: 0, behavior: "instant" });
          }
        }
      });
      setTimeout(() => {
        m.classList.remove("opening");
        if (sheet) {
          sheet.style.willChange = "";
        }
      }, 960);
    } else {
      if (m.classList.contains("embedded-datepicker-modal")) {
        m.style.display = "flex";
      }
      m.classList.remove("closing");
      requestAnimationFrame(() => {
        m.classList.add("open");
      });
    }
    document.body.style.overflow = "hidden";
    traceApp("openModal", { id });
    traceLayoutSnapshot(`openModal:${id}`);
    scheduleGuideResume(`openModal:${id}`, id === "addModal" ? 420 : 260);
  }
}

function restoreHomeHeroIfNeeded() {
  if (currentTab !== "home" || simpleMode) return;
  const heroWrap = document.getElementById("heroCardWrap");
  if (!heroWrap) return;
  heroWrap.style.display = "";
  heroWrap.style.visibility = "visible";
  heroWrap.style.opacity = "1";
  updateHeroTrendText();
  forceHeroChipLayout(heroWrap);
  updateHeroChipLabels(heroWrap);
  updateHeroDebugOverlay();
}

function ensureHomeHeroStable(attempts = 6, delay = 120) {
  restoreHomeHeroIfNeeded();
  updateHeroDebugOverlay();
  if (attempts <= 1) return;
  setTimeout(() => ensureHomeHeroStable(attempts - 1, delay), delay);
}

function createHeroWrapNode() {
  const { balD, incD, expD, salD } = getTopBlockDisplayValues();
  const s = sym();
  const wrap = document.createElement("div");
  wrap.className = "hero-card-wrap";
  wrap.id = "heroCardWrap";
  wrap.innerHTML = `
    <div
      id="balanceCard"
      class="balance-card balance-card-wide"
      data-type="balance"
      role="button"
      tabindex="0"
    >
      <div id="balanceHeroFocus">
        <div class="hero-label" data-i18n="balance">${t("balance")}</div>
        <div class="hero-value" id="balanceValue">${balD.toFixed(2)} ${s}</div>
        <div class="hero-sub" id="heroTrend"></div>
      </div>
      <div class="hero-chips">
        <div
          id="incomeCard"
          class="hero-chip hc-income"
          data-type="income"
          role="button"
          tabindex="0"
        >
          <div class="hc-label">
            <span class="hc-icon">📈</span>
            <span class="hc-label-text" id="incomeHeroLabel"></span>
          </div>
          <div class="hc-value" id="incomeValue">${incD.toFixed(2)} ${s}</div>
        </div>
        <div
          id="expenseCard"
          class="hero-chip hc-expense"
          data-type="expense"
          role="button"
          tabindex="0"
        >
          <div class="hc-label">
            <span class="hc-icon">📉</span>
            <span class="hc-label-text" id="expenseHeroLabel"></span>
          </div>
          <div class="hc-value" id="expenseValue">${expD.toFixed(2)} ${s}</div>
        </div>
        <div
          id="salaryCard"
          class="hero-chip hc-salary"
          data-type="salary"
          role="button"
          tabindex="0"
        >
          <div class="hc-label">
            <span class="hc-icon">💼</span>
            <span class="hc-label-text" id="salaryHeroLabel"></span>
          </div>
          <div class="hc-value" id="salaryValue">${salD.toFixed(2)} ${s}</div>
        </div>
      </div>
    </div>
  `;
  updateHeroTrendText();
  updateHeroChipLabels(wrap);
  return wrap;
}

function ensureHeroWrapAnchor() {
  const heroWrap = document.getElementById("heroCardWrap");
  heroWrapAnchor = document.getElementById("heroCardAnchor") || heroWrapAnchor;
  if (!heroWrapAnchor || !heroWrapAnchor.isConnected) {
    const header = document.querySelector(".app-header");
    const mainScroll = document.querySelector(".main-scroll");
    heroWrapAnchor = document.createElement("div");
    heroWrapAnchor.id = "heroCardAnchor";
    if (header && header.parentNode) {
      header.parentNode.insertBefore(
        heroWrapAnchor,
        mainScroll || header.nextSibling,
      );
    }
  }
  if (heroWrap) {
    if (heroWrapAnchor && heroWrap.parentNode === heroWrapAnchor.parentNode) {
      heroWrapAnchor.parentNode?.insertBefore(heroWrapAnchor, heroWrap);
    }
    return heroWrap;
  }
  const recreated = createHeroWrapNode();
  if (heroWrapAnchor?.parentNode) {
    heroWrapAnchor.parentNode.insertBefore(
      recreated,
      heroWrapAnchor.nextSibling,
    );
  }
  return recreated;
}

function mountHeroIntoHome() {
  const heroWrap = ensureHeroWrapAnchor();
  const mainContent = document.getElementById("mainContent");
  if (!heroWrap || !mainContent) return;
  if (heroWrap.parentNode !== mainContent) {
    mainContent.insertBefore(heroWrap, mainContent.firstChild || null);
  }
}

function unmountHeroFromHome() {
  const heroWrap = ensureHeroWrapAnchor();
  if (!heroWrap || !heroWrapAnchor) return;
  if (heroWrap.parentNode !== heroWrapAnchor.parentNode) {
    heroWrapAnchor.parentNode?.insertBefore(
      heroWrap,
      heroWrapAnchor.nextSibling,
    );
  }
}

let suspendHomeHeroLifecycle = false;

function setSuspendHomeHeroLifecycle(value) {
  suspendHomeHeroLifecycle = !!value;
}

function wrapHomeHeroLifecycleFunction(fnName) {
  const fn = globalThis[fnName];
  if (typeof fn !== "function" || fn.__homeHeroLifecycleWrapped) return;
  const wrapped = function (...args) {
    if (suspendHomeHeroLifecycle) return;
    return fn.apply(this, args);
  };
  wrapped.__homeHeroLifecycleWrapped = true;
  wrapped.__homeHeroLifecycleOriginal = fn;
  globalThis[fnName] = wrapped;
}

[
  "restoreHomeHeroIfNeeded",
  "ensureHomeHeroStable",
  "updateHeroTrendText",
  "updateHeroChipLabels",
  "forceHeroChipLayout",
  "mountHeroIntoHome",
  "unmountHeroFromHome",
].forEach(wrapHomeHeroLifecycleFunction);

function ensureHeroWrapGuard() {
  const heroWrap = document.getElementById("heroCardWrap");
  if (!heroWrap) return;
  heroWrapObserver?.disconnect();
  heroWrapObserver = new MutationObserver(() => {
    if (currentTab !== "home" || simpleMode) return;
    const hiddenByStyle =
      heroWrap.style.display === "none" ||
      heroWrap.style.visibility === "hidden" ||
      heroWrap.style.opacity === "0";
    if (hiddenByStyle) {
      restoreHomeHeroIfNeeded();
    }
  });
  heroWrapObserver.observe(heroWrap, {
    attributes: true,
    attributeFilter: ["style", "class"],
  });
}

function updateHeroDebugOverlay() {
  if (localStorage.getItem("heroDebug") !== "1") {
    document.getElementById("heroDebugOverlay")?.remove();
    return;
  }
  let dbg = document.getElementById("heroDebugOverlay");
  if (!dbg) {
    dbg = document.createElement("div");
    dbg.id = "heroDebugOverlay";
    dbg.style.cssText =
      "position:fixed;left:8px;top:8px;z-index:20000;background:rgba(0,0,0,.82);color:#fff;padding:8px 10px;border-radius:10px;font:12px/1.35 monospace;max-width:calc(100vw - 16px);white-space:pre-wrap;pointer-events:none;";
    document.body.appendChild(dbg);
  }
  const heroWrap = document.getElementById("heroCardWrap");
  const parentId =
    heroWrap?.parentElement?.id ||
    heroWrap?.parentElement?.className ||
    "(none)";
  const rect =
    heroWrap && heroWrap.getBoundingClientRect
      ? heroWrap.getBoundingClientRect()
      : null;
  dbg.textContent =
    "tab=" +
    currentTab +
    " | simple=" +
    simpleMode +
    "\nhero=" +
    !!heroWrap +
    " | parent=" +
    parentId +
    "\ndisplay=" +
    (heroWrap?.style.display || "(empty)") +
    " | vis=" +
    (heroWrap?.style.visibility || "(empty)") +
    " | op=" +
    (heroWrap?.style.opacity || "(empty)") +
    "\nrect=" +
    (rect ? Math.round(rect.width) + "x" + Math.round(rect.height) : "none");
}

function traceApp(event, details = {}) {
  if (!APP_TRACE_ENABLED) return;
  const timestamp = new Date().toLocaleTimeString("en-GB", {
    hour12: false,
  });
  let detailText = "";
  try {
    detailText = Object.keys(details).length
      ? " " + JSON.stringify(details)
      : "";
  } catch (e) {
    detailText = " [unserializable]";
  }
  const line = `${timestamp} ${event}${detailText}`;
  console.log("[BPTRACE]", line);
  try {
    if (
      window.BudgetPROTrace &&
      typeof window.BudgetPROTrace.log === "function"
    ) {
      window.BudgetPROTrace.log(line);
    }
  } catch (e) {}
  appTraceLines.push(line);
  if (appTraceLines.length > 12) appTraceLines.shift();

  if (!appTracePanel) {
    appTracePanel = document.createElement("div");
    appTracePanel.id = "appTracePanel";
    appTracePanel.style.cssText =
      "position:fixed;left:8px;right:8px;bottom:88px;z-index:20001;" +
      "background:rgba(0,0,0,.82);color:#fff;border-radius:12px;" +
      "padding:8px 10px;font:11px/1.35 monospace;max-height:180px;" +
      "overflow:auto;white-space:pre-wrap;pointer-events:none;" +
      "box-shadow:0 10px 30px rgba(0,0,0,.35);";
    document.body.appendChild(appTracePanel);
  }
  appTracePanel.textContent = appTraceLines.join("\n");
}

function attachAppTraceObservers() {
  if (!APP_TRACE_ENABLED) return;
  const mainContent = document.getElementById("mainContent");
  if (mainContent) {
    appTraceMainObserver?.disconnect();
    appTraceMainObserver = new MutationObserver(() => {
      const heroWrap = document.getElementById("heroCardWrap");
      traceApp("mainContent-mutated", {
        heroExists: !!heroWrap,
        heroParent:
          heroWrap?.parentElement?.id ||
          heroWrap?.parentElement?.className ||
          null,
        childCount: mainContent.children.length,
      });
      attachAppTraceObservers();
    });
    appTraceMainObserver.observe(mainContent, { childList: true });
  }

  const heroWrap = document.getElementById("heroCardWrap");
  if (heroWrap) {
    appTraceHeroObserver?.disconnect();
    appTraceHeroObserver = new MutationObserver(() => {
      const rect = heroWrap.getBoundingClientRect?.();
      traceApp("hero-mutated", {
        display: heroWrap.style.display || "",
        visibility: heroWrap.style.visibility || "",
        opacity: heroWrap.style.opacity || "",
        parent:
          heroWrap.parentElement?.id ||
          heroWrap.parentElement?.className ||
          null,
        rect: rect
          ? `${Math.round(rect.width)}x${Math.round(rect.height)}`
          : null,
      });
    });
    appTraceHeroObserver.observe(heroWrap, {
      attributes: true,
      attributeFilter: ["style", "class"],
    });
  }
}

function installHomeLayoutRuntimeAudit() {
  if (window.__homeLayoutRuntimeAuditInstalled) return;
  window.__homeLayoutRuntimeAuditInstalled = true;

  const stylePropsToTrace = new Set([
    "height",
    "min-height",
    "minHeight",
    "max-height",
    "maxHeight",
    "display",
    "transform",
    "scale",
    "flex",
    "flex-grow",
    "flexGrow",
    "flex-shrink",
    "flexShrink",
    "grid-template-rows",
    "gridTemplateRows",
    "padding",
    "padding-top",
    "paddingTop",
    "padding-right",
    "paddingRight",
    "padding-bottom",
    "paddingBottom",
    "padding-left",
    "paddingLeft",
    "margin",
    "margin-top",
    "marginTop",
    "margin-right",
    "marginRight",
    "margin-bottom",
    "marginBottom",
    "margin-left",
    "marginLeft",
  ]);
  const resizeState = new WeakMap();
  const observedParentNodes = new WeakSet();
  const writeState = new WeakMap();
  let resizeObserver = null;
  let bodyObserver = null;
  let visualViewportState = null;

  const nowTs = () => new Date().toISOString();
  const getStack = () => {
    const stack = new Error().stack || "";
    return stack
      .split("\n")
      .slice(2)
      .join("\n");
  };
  const describeEl = (el) => {
    if (!el) return "(null)";
    if (el === document.documentElement) return "html";
    if (el === document.body) return "body";
    const parts = [el.tagName?.toLowerCase() || "node"];
    if (el.id) parts.push(`#${el.id}`);
    if (el.classList?.length) {
      parts.push("." + Array.from(el.classList).join("."));
    }
    return parts.join("");
  };
  const getNearestScrollContainer = () => {
    const balanceCard = document.getElementById("balanceCard");
    let node = balanceCard?.parentElement || null;
    while (node && node !== document.body) {
      const cs = getComputedStyle(node);
      const overflowValue = `${cs.overflow} ${cs.overflowY} ${cs.overflowX}`;
      if (/(auto|scroll|overlay)/.test(overflowValue)) return node;
      node = node.parentElement;
    }
    return document.scrollingElement || document.documentElement;
  };
  const getTrackedNodes = () => {
    const tracked = [
      document.getElementById("balanceCard"),
      document.getElementById("heroCardWrap"),
      document.getElementById("mainContent"),
      document.getElementById("homeTab"),
      getNearestScrollContainer(),
      document.documentElement,
      document.body,
    ].filter(Boolean);
    return Array.from(new Set(tracked));
  };
  const isTrackedElement = (el) => getTrackedNodes().includes(el);
  const findOwnerByStyle = (styleDecl) => {
    const nodes = getTrackedNodes();
    for (const node of nodes) {
      if (node?.style === styleDecl) return node;
    }
    return null;
  };
  const recordWrite = (el, payload) => {
    if (!el) return;
    writeState.set(el, {
      timestamp: Date.now(),
      ...payload,
    });
  };
  const getRecentWrite = (el) => {
    const last = writeState.get(el);
    if (!last) return null;
    if (Date.now() - last.timestamp > 2000) return null;
    return last;
  };
  const logJson = (label, payload) => {
    console.log(`[${label}] ${JSON.stringify(payload)}`);
  };
  const observeParentChain = () => {
    const balanceCard = document.getElementById("balanceCard");
    let node = balanceCard?.parentElement || null;
    while (node) {
      if (!observedParentNodes.has(node)) {
        const parentObserver = new MutationObserver((mutations) => {
          mutations.forEach((mutation) => {
            if (mutation.type !== "attributes") return;
            const target = mutation.target;
            const attrName = mutation.attributeName || null;
            logJson("PARENT_LAYOUT_CHANGE", {
              timestamp: nowTs(),
              element: describeEl(target),
              attribute: attrName,
              oldValue: mutation.oldValue ?? null,
              newValue: target.getAttribute(attrName),
              cssText: target.style?.cssText || "",
              className: target.className || "",
            });
          });
        });
        parentObserver.observe(node, {
          attributes: true,
          attributeOldValue: true,
          attributeFilter: ["style", "class"],
        });
        observedParentNodes.add(node);
      }
      if (node === document.body) break;
      node = node.parentElement;
    }
  };
  const observeResizeTargets = () => {
    if (!resizeObserver) {
      resizeObserver = new ResizeObserver((entries) => {
        entries.forEach((entry) => {
          const target = entry.target;
          const nextWidth = Math.round(entry.contentRect.width);
          const nextHeight = Math.round(entry.contentRect.height);
          const prev = resizeState.get(target) || {
            width: null,
            height: null,
          };
          const recentWrite = getRecentWrite(target);
          logJson("RESIZE_TRACE", {
            timestamp: nowTs(),
            element: describeEl(target),
            width: nextWidth,
            height: nextHeight,
            oldWidth: prev.width,
            oldHeight: prev.height,
            stack: recentWrite?.stack || null,
            recentWriteProperty: recentWrite?.property || null,
            recentWriteValue: recentWrite?.newValue || null,
          });
          resizeState.set(target, {
            width: nextWidth,
            height: nextHeight,
          });
        });
      });
    }
    getTrackedNodes().forEach((node) => {
      if (!node || node.nodeType !== 1) return;
      try {
        resizeObserver.observe(node);
      } catch (e) {}
    });
  };
  const emitVisualViewportTrace = (reason) => {
    const vv = window.visualViewport;
    if (!vv) return;
    const next = {
      width: Math.round(vv.width || 0),
      height: Math.round(vv.height || 0),
      offsetTop: Math.round(vv.offsetTop || 0),
      pageTop: Math.round(vv.pageTop || 0),
      scale: Number(vv.scale || 0),
    };
    if (!visualViewportState) {
      visualViewportState = next;
      logJson("VISUAL_VIEWPORT_TRACE", {
        timestamp: nowTs(),
        reason,
        ...next,
      });
      return;
    }
    const changed = Object.keys(next).some((key) => {
      if (key === "scale") {
        return Math.abs(next[key] - visualViewportState[key]) >= 0.01;
      }
      return Math.abs(next[key] - visualViewportState[key]) >= 1;
    });
    if (!changed) return;
    logJson("VISUAL_VIEWPORT_TRACE", {
      timestamp: nowTs(),
      reason,
      ...next,
      oldWidth: visualViewportState.width,
      oldHeight: visualViewportState.height,
      oldOffsetTop: visualViewportState.offsetTop,
      oldPageTop: visualViewportState.pageTop,
      oldScale: visualViewportState.scale,
    });
    visualViewportState = next;
  };
  window.visualViewport?.addEventListener("resize", () =>
    emitVisualViewportTrace("resize"),
  );
  window.visualViewport?.addEventListener("scroll", () =>
    emitVisualViewportTrace("scroll"),
  );
  emitVisualViewportTrace("init");

  if (!window.__homeLayoutRuntimeAuditPatched) {
    window.__homeLayoutRuntimeAuditPatched = true;
    const styleProto = CSSStyleDeclaration.prototype;
    const originalSetProperty = styleProto.setProperty;
    styleProto.setProperty = function (name, value, priority) {
      const owner = findOwnerByStyle(this);
      if (owner && stylePropsToTrace.has(String(name))) {
        const stack = getStack();
        recordWrite(owner, {
          property: String(name),
          oldValue: this.getPropertyValue(name),
          newValue: value == null ? "" : String(value),
          stack,
        });
        logJson("LAYOUT_STYLE_WRITE", {
          timestamp: nowTs(),
          element: describeEl(owner),
          property: String(name),
          oldValue: this.getPropertyValue(name),
          newValue: value == null ? "" : String(value),
          cssText: owner.style.cssText || "",
          stack,
        });
      }
      return originalSetProperty.call(this, name, value, priority);
    };
    [
      "height",
      "minHeight",
      "maxHeight",
      "display",
      "transform",
      "scale",
      "flex",
      "flexGrow",
      "flexShrink",
      "gridTemplateRows",
      "padding",
      "paddingTop",
      "paddingRight",
      "paddingBottom",
      "paddingLeft",
      "margin",
      "marginTop",
      "marginRight",
      "marginBottom",
      "marginLeft",
    ].forEach((prop) => {
      const desc = Object.getOwnPropertyDescriptor(styleProto, prop);
      if (!desc?.set || !desc.get || desc.set.__homeLayoutAuditWrapped) return;
      const originalSetter = desc.set;
      const originalGetter = desc.get;
      const wrappedSetter = function (value) {
        const owner = findOwnerByStyle(this);
        if (owner) {
          const stack = getStack();
          recordWrite(owner, {
            property: prop,
            oldValue: originalGetter.call(this),
            newValue: value == null ? "" : String(value),
            stack,
          });
          logJson("LAYOUT_STYLE_WRITE", {
            timestamp: nowTs(),
            element: describeEl(owner),
            property: prop,
            oldValue: originalGetter.call(this),
            newValue: value == null ? "" : String(value),
            cssText: owner.style.cssText || "",
            stack,
          });
        }
        return originalSetter.call(this, value);
      };
      wrappedSetter.__homeLayoutAuditWrapped = true;
      Object.defineProperty(styleProto, prop, {
        configurable: desc.configurable,
        enumerable: desc.enumerable,
        get: originalGetter,
        set: wrappedSetter,
      });
    });
  }

  const scan = () => {
    observeResizeTargets();
    observeParentChain();
  };
  scan();
  bodyObserver = new MutationObserver(scan);
  bodyObserver.observe(document.body || document.documentElement, {
    childList: true,
    subtree: true,
  });
  window.__homeLayoutRuntimeAudit = {
    getTrackedNodes,
  };
}

if (document.body) {
  installHomeLayoutRuntimeAudit();
} else {
  window.addEventListener("DOMContentLoaded", installHomeLayoutRuntimeAudit, {
    once: true,
  });
}

function describeTraceTarget(target) {
  if (!target) return "unknown";
  const el = target.closest?.(
    "#fabBtn, #fabBtnSimple, .modal-close, .modal-overlay, .btn-primary, .btn-secondary, .nav-btn, .hero-chip, .balance-card-wide, .balance-row, #appLogoBtn",
  );
  if (!el) return null;
  return (
    el.id ||
    el.dataset?.tab ||
    el.dataset?.type ||
    el.className
      ?.toString()
      ?.split(" ")
      .filter(Boolean)
      .slice(0, 3)
      .join(".") ||
    el.tagName
  );
}

function rectSummary(el) {
  if (!el || !el.getBoundingClientRect) return null;
  const r = el.getBoundingClientRect();
  return {
    x: Math.round(r.x),
    y: Math.round(r.y),
    w: Math.round(r.width),
    h: Math.round(r.height),
  };
}

function elementState(id) {
  const el = document.getElementById(id);
  if (!el) return { exists: false };
  return {
    exists: true,
    parent:
      el.parentElement?.id || el.parentElement?.className?.toString?.() || null,
    display: el.style.display || "",
    visibility: el.style.visibility || "",
    opacity: el.style.opacity || "",
    rect: rectSummary(el),
  };
}

function traceLayoutSnapshot(reason) {
  if (!APP_TRACE_ENABLED) return;
  const mainContent = document.getElementById("mainContent");
  traceApp("layout-snapshot", {
    reason,
    tab: currentTab,
    simpleMode,
    mainContentChildren: mainContent?.children?.length ?? null,
    mainContentRect: rectSummary(mainContent),
    hero: elementState("heroCardWrap"),
    balance: elementState("balanceCard"),
    income: elementState("incomeCard"),
    expense: elementState("expenseCard"),
    salary: elementState("salaryCard"),
  });
}

function scheduleBootLayoutTracing() {
  if (!APP_TRACE_ENABLED) return;
  appBootTraceTimers.forEach((id) => clearTimeout(id));
  appBootTraceTimers = [];
  [0, 80, 180, 320, 600, 1000, 1600, 2400].forEach((delay) => {
    const timerId = setTimeout(
      () => traceLayoutSnapshot(`boot+${delay}ms`),
      delay,
    );
    appBootTraceTimers.push(timerId);
  });
}

function scheduleHomeRecoveryAfterAddCancel() {
  addModalRecoveryTimers.forEach((id) => clearTimeout(id));
  addModalRecoveryTimers = [];
  [60, 220, 520, 900].forEach((delay) => {
    const timerId = setTimeout(() => {
      if (document.getElementById("addModal")) return;
      if (currentTab !== "home" || simpleMode) return;
      renderHome();
      updateTopBlocks();
    }, delay);
    addModalRecoveryTimers.push(timerId);
  });
}

function closeModal(id) {
  const m = document.getElementById(id);
  if (m) {
    if (m.classList.contains("closing")) return;
    traceApp("closeModal-start", {
      id,
      addModalCommitted,
      currentTab,
      simpleMode,
    });
    const shouldRestoreHomeAfterAddCancel =
      id === "addModal" &&
      !addModalCommitted &&
      currentTab === "home" &&
      !simpleMode;
    if (id === "addModal") {
      const sheet = m.querySelector(".add-modal-sheet");
      addModalLastClosedAt = Date.now();
      m.classList.remove("open");
      m.classList.add("closing");
      if (sheet) {
        sheet.classList.remove("dragging");
      }
      setTimeout(() => {
        m.style.display = "none";
        m.remove();
      }, 500);
    } else {
      m.classList.remove("open");
      setTimeout(() => m.remove(), 350);
    }
    const keepBodyLocked = !!document.querySelector(
      ".modal-overlay.open, .add-modal-host.open",
    );
    document.body.style.overflow = keepBodyLocked ? "hidden" : "";
    traceLayoutSnapshot(`closeModal:${id}`);
    updateHeroDebugOverlay();
    if (id === "addModal") addModalCommitted = false;
    setTimeout(() => ensureHomeHeroStable(), 20);
    if (shouldRestoreHomeAfterAddCancel) {
      traceApp("closeModal-recover-home", { id });
      scheduleHomeRecoveryAfterAddCancel();
    }
    scheduleGuideResume(`closeModal:${id}`, id === "addModal" ? 520 : 300);
  }
}

