function isAuthenticated() {
  const session = getAuthSession("isAuthenticated");
  if (!session?.access_token) return false;
  if (!session?.expires_at) return false;
  const now = Date.now();
  const isValid = session.expires_at * 1000 > now;
  if (!isValid) {
    logAuthDiag("[AUTH_EXPIRED]", "isAuthenticated", session);
    if (session.refresh_token) {
      logAuthDiag("[AUTH_REFRESH]", "isAuthenticated:no-auto-refresh", session);
    }
  }
  return isValid;
}

async function handleAuthCallback() {
  const hash = pendingAppUrlAuthHash || window.location.hash || "";
  pendingAppUrlAuthHash = "";
  if (!hash || hash.startsWith("#share=")) return false;

  const params = new URLSearchParams(hash.slice(1));
  const errorCode = params.get("error_code") || "";
  const error = params.get("error") || "";
  if (errorCode === "otp_expired" || error === "access_denied") {
    const expiredSession = getAuthSession("handleAuthCallback:expired-link");
    logAuthDiag("[AUTH_EXPIRED]", "handleAuthCallback:expired-link", expiredSession);
    localStorage.removeItem(AUTH_PENDING_EMAIL_KEY);
    history.replaceState(
      null,
      "",
      window.location.pathname + window.location.search,
    );
    showToast(
      {
        ru: "Ссылка входа истекла. Запросите новое письмо.",
        en: "Login link expired. Request a new email.",
        ka: "შესვლის ბმულს ვადა გაუვიდა. მოითხოვეთ ახალი წერილი.",
      }[currentLang],
      "error",
    );
    return false;
  }
  const accessToken = params.get("access_token") || "";
  const refreshToken = params.get("refresh_token") || "";
  const expiresIn = parseInt(params.get("expires_in") || "0", 10);

  if (!accessToken || !refreshToken || !expiresIn) return false;

  const payload = parseJwtPayload(accessToken);
  const email =
    payload && typeof payload.email === "string" ? payload.email : "";
  const authUserId =
    String(
      (payload && typeof payload.sub === "string" ? payload.sub : "") || "",
    ).trim() || null;

console.log("[BP_AUTH_EMAIL]", email);

saveAuthSession({
    access_token: accessToken,
    refresh_token: refreshToken,
    expires_at: Math.floor(Date.now() / 1000) + expiresIn,
    email,
    authUserId,
  }, "handleAuthCallback");

console.log(
  "[BP_AUTH_SESSION]",
  JSON.stringify(getAuthSession("handleAuthCallback:after-save")),
);
logAuthDiag("[AUTH_REFRESH]", "handleAuthCallback:received-refresh-token", {
  email,
  expires_at: Math.floor(Date.now() / 1000) + expiresIn,
});

  setGuestMode(false);
  localStorage.removeItem(CREATOR_WELCOME_SHOWN_KEY);
  localStorage.removeItem(AUTH_PENDING_EMAIL_KEY);
  history.replaceState(
    null,
    "",
    window.location.pathname + window.location.search,
  );
  return true;
}

async function sendMagicLink(email) {
  const normalizedEmail = String(email || "").trim().toLowerCase();

  console.log("[BP_SEND_EMAIL]", normalizedEmail);

  const response = await fetch(
    "https://budget-pro-lski.vercel.app/api/auth/magic-link",
    {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
    },
    body: JSON.stringify({ email: normalizedEmail }),
  });

  let data = null;
  try {
    data = await response.json();
  } catch (e) {
    data = null;
  }

  if (!response.ok) {
    throw createMagicLinkError(response.status, data, "magic_link_send_failed");
  }

  console.log("[BP_MAGIC_RESPONSE]", response.status, JSON.stringify(data));

  if (data && data.ok === false) {
    throw createMagicLinkError(response.status, data, "magic_link_send_failed");
  }

  localStorage.setItem(AUTH_PENDING_EMAIL_KEY, normalizedEmail);
  return data || { ok: true };
}

